class Solution:
    def combinationSum3(self, k: int, n: int) -> List[List[int]]:
        ans, path = [], []
        def dfs(start, rem, left):
            if left == 0:
                if rem == 0:
                    ans.append(path[:])
                return
            if rem <= 0:
                return
            for i in range(start, 10):
                if i > rem:
                    break
                path.append(i)
                dfs(i + 1, rem - i, left - 1)
                path.pop()
        dfs(1, n, k)
        return ans

