class Solution {
    vector<vector<int>> ans;
    vector<int> path;
    void dfs(int start, int rem, int k) {
        if (k == 0) { if (rem == 0) ans.push_back(path); return; }
        if (rem <= 0) return;
        for (int i = start; i <= 9; i++) {
            if (i > rem) break;
            path.push_back(i);
            dfs(i + 1, rem - i, k - 1);
            path.pop_back();
        }
    }
public:
    vector<vector<int>> combinationSum3(int k, int n) {
        dfs(1, n, k);
        return ans;
    }
};

